impl PageTableEntry {
    pub fn is_cow(&self) -> bool {
        self.bits & (1 << 9) != 0  // 使用第9位标记 COW
    }
    pub fn set_cow(&mut self) {
        (*self).bits = self.bits | (1 << 9);
    }
    pub fn reset_cow(&mut self) {
        (*self).bits = self.bits & !(1 << 9);
